// STRY0137140 - Master Story for "Task Manager Dashboard"- All Performance Improvement and Clean up Changes Added comments in all of the script files
// 2.8.3 | 2023-06-21 |raj | STRY0141431 - Assigned GHA After Creating Top OU
// 2.8.3 | 2023-05-24 |raj | STRY0140267 - Task Administrator Email 
//
// Script Continued Below
(function executeRule(current, previous /*null when async*/) {

	if(current.operation() == "insert"){
		// STRY0141431 - if top OU, add the current user as a member and make them GHA
		if(current.parent.nil()){
			new Organization_uiAction().newTopOU_addUser_asGHA(current);
		}
	}

	if(current.operation() == "update"){
		// need to update all childern if the parent changed
		// STRY0108760 - 2.6.400 patch
		if((current.parent != previous.parent) || 
			(current.office_level != current.parent.office_level + 1) || 
			(current.office_level != previous.office_level || 
			current.u_all_ancestors_organizations != previous.u_all_ancestors_organizations)){

			// STRY0137140
			var orgScripts = new OrganizationalScripts();
			var grChildOus = new GlideRecord('x_153465_discovert_discover_office_hierarchy');
			grChildOus.addQuery('parent', current.sys_id);
			grChildOus.query();
			while (grChildOus.next()){
				grChildOus.office_level = current.office_level + 1;
				// STRY0137140
				var parentId = current.getUniqueValue();
				var ancestors = orgScripts.getAncestors(parentId);
				grChildOus.u_all_ancestors_organizations = ancestors;

				grChildOus.update();
			}
			new OrganizationalScripts().setTopOUTaskAdministratorsForOU(previous.u_top_ou);
			new OrganizationalScripts().setTopOUTaskAdministratorsForOU(current.u_top_ou);
		}
	}

	if(current.operation() == "delete"){
		// need to determine if deleting all children or pushing the children up a level to the parent of the row being deleted

	}

})(current, previous);
